import{_ as a,o as t,c as o,ae as r}from"./chunks/framework.B6gjLfeO.js";const m=JSON.parse('{"title":"ROI Hub File Templates for Importing Cost Data","description":"","frontmatter":{"title":"ROI Hub File Templates for Importing Cost Data","slug":"new-roi-hub-file-templates-for-importing-cost-data"},"headers":[],"relativePath":"account-hub/new-roi-hub-file-templates-for-importing-cost-data.md","filePath":"account-hub/new-roi-hub-file-templates-for-importing-cost-data.md"}'),i={name:"account-hub/new-roi-hub-file-templates-for-importing-cost-data.md"};function n(l,e,s,d,p,c){return t(),o("div",null,[...e[0]||(e[0]=[r('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>File templates for ROI Hub make it easier to import your cost data for an ad partner. File templates are useful because they help map your custom cost data fields to our standard Branch fields.</p><p>Instead of needing to change your cost data to match Branch&#39;s required formatting when importing it, you can now create a file template. A file template is how Branch knows how to translate your cost data field names into ours.</p><p>Moving forward, you will need to make sure an ad partner has an associated file template created for it <strong>before</strong> you can <a href="./cost-data-via-file-upload.html">upload a CSV cost data file</a> or <a href="./cost-data-via-email-import.html">set up email importing</a> for that ad partner.</p><h2 id="field-mapping" tabindex="-1">Field Mapping <a class="header-anchor" href="#field-mapping" aria-label="Permalink to &quot;Field Mapping&quot;">​</a></h2><p>When creating a file template, you will need to upload a sample file that contains the fields you expect in your cost data. Put these fields as your column headers, and populate the rows with some sample data that is similar to what you would actually send to Branch.</p><p>At this point, you will need to map your field names to Branch field names. You can ask Branch to try to automatically fill these in for you with the <strong>Auto Map Fields</strong> button, and then make any corrections you need to.</p><p>.png)</p><p>Please note that the following fields are <strong>required</strong>:</p><ul><li><code>date</code></li><li><code>campaign_name</code></li><li><code>cost</code></li></ul><h2 id="learn-more" tabindex="-1">Learn More <a class="header-anchor" href="#learn-more" aria-label="Permalink to &quot;Learn More&quot;">​</a></h2><p>See our guide for detailed steps on how to <a href="./templates-for-cost-data.html">create and use a file template</a> for more information.</p>',12)])])}const h=a(i,[["render",n]]);export{m as __pageData,h as default};
